const body = $input.first().json.body || $input.first().json;
const { tenant_id, config } = body;

if (!tenant_id || !config) {
  return [{ json: { success: false, error: 'tenant_id and config are required' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.configs) staticData.configs = {};

staticData.configs[tenant_id] = {
  ...config,
  tenant_id,
  updated_at: new Date().toISOString()
};

return [{ json: { success: true, tenant_id, updated_at: staticData.configs[tenant_id].updated_at } }];
